Answer: You can use a closure to do this.

\begin{code}
func sql(query: String, transformation: (([PostgresqlRow]) -> ([T]))?) -> [T] {
    let result = sql(query: query)
    if let transformation = transformation {
        result = result.map { transformation($0) }
    }
    return result
}
\end{code}

You can then call it like this:

\begin{code}
sql("select \* from items", transformation: { $0.map { ItemTable.from(row: $0) } })
\end{code}

